SELECT /* base.ec.pd :: PdReviewAttach :: selectList */ a.* , att.file_nm AS attach_nm , ste.site_nm AS site_nm , cd_mt.code_label AS media_type_cd_nm FROM pd_review_attach a LEFT JOIN pd_review r ON r.review_id = a.review_id LEFT JOIN sy_attach att ON att.attach_id = a.attach_id LEFT JOIN sy_site ste ON ste.site_id = a.site_id LEFT JOIN sy_code cd_mt ON cd_mt.code_grp = 'MEDIA_TYPE' AND cd_mt.code_value = a.media_type_cd
ORDER BY a.review_attach_id ASC ORDER BY a.review_attach_id DESC ORDER BY a.reg_date ASC ORDER BY a.reg_date DESC ORDER BY a.sort_ord ASC, a.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.pd :: PdReviewAttach :: selectPageList */ a.* , att.file_nm AS attach_nm , ste.site_nm AS site_nm , cd_mt.code_label AS media_type_cd_nm FROM pd_review_attach a LEFT JOIN pd_review r ON r.review_id = a.review_id LEFT JOIN sy_attach att ON att.attach_id = a.attach_id LEFT JOIN sy_site ste ON ste.site_id = a.site_id LEFT JOIN sy_code cd_mt ON cd_mt.code_grp = 'MEDIA_TYPE' AND cd_mt.code_value = a.media_type_cd
ORDER BY a.review_attach_id ASC ORDER BY a.review_attach_id DESC ORDER BY a.reg_date ASC ORDER BY a.reg_date DESC ORDER BY a.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

